const amqp = require('amqplib');
const { exec } = require('child_process');
const { Client } = require('pg');

const RABBITMQ_URL = 'amqp://localhost';
const QUEUE_NAME = 'task_queue';
const DB_CONFIG = {
  user: 'dbuser',
  host: 'localhost',
  database: 'dbname',
  password: 'dbpassword',
  port: 5432,
};

async function processMessage(msg) {
  try {
    const content = JSON.parse(msg.content.toString());
    const { type, payload } = content;

    switch (type) {
      case 'database_query':
        await executeDatabaseQuery(payload);
        break;
      case 'system_command':
        executeSystemCommand(payload);
        break;
      default:
        console.error('Unknown message type:', type);
    }
  } catch (error) {
    console.error('Error processing message:', error);
  }
}

async function executeDatabaseQuery(payload) {
  const client = new Client(DB_CONFIG);
  try {
    await client.connect();
    const res = await client.query(payload.query, payload.params);
    console.log('Query result:', res.rows);
  } catch (error) {
    console.error('Database query error:', error);
  } finally {
    await client.end();
  }
}

function executeSystemCommand(payload) {
  exec(payload.command, (error, stdout, stderr) => {
    if (error) {
      console.error('Command execution error:', error);
      return;
    }
    if (stderr) {
      console.error('Command stderr:', stderr);
      return;
    }
    console.log('Command stdout:', stdout);
  });
}

async function start() {
  try {
    const connection = await amqp.connect(RABBITMQ_URL);
    const channel = await connection.createChannel();
    await channel.assertQueue(QUEUE_NAME, { durable: true });

    console.log('Waiting for messages in queue:', QUEUE_NAME);
    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg !== null) {
        await processMessage(msg);
        channel.ack(msg);
      }
    });
  } catch (error) {
    console.error('Error starting microservice:', error);
  }
}

start();